@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar">
        <span class="stat-item"><strong>Total:</strong> @allTasks.Count</span>
        <span class="stat-item"><strong>To Do:</strong> @GetColumnTasks("To Do").Count</span>
        <span class="stat-item"><strong>In Progress:</strong> @GetColumnTasks("In Progress").Count</span>
        <span class="stat-item"><strong>Done:</strong> @GetColumnTasks("Done").Count</span>
        <span class="stat-item stat-overdue"><strong>Overdue:</strong> @allTasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="search-bar">
        <input type="text" class="form-control" placeholder="Search tasks by title..." @bind="searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="board-container">
        @foreach (var column in columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            <div class="board-column">
                <div class="column-header">
                    <h4>@column <span class="badge bg-secondary">@tasks.Count</span></h4>
                </div>
                <div class="column-body">
                    @foreach (var task in tasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="badge priority-@task.Priority.ToLower()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (GetColumnIndex(column) > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => MoveTask(task, -1)" disabled="@isProcessing">← Move Left</button>
                                }
                                @if (GetColumnIndex(column) < columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => MoveTask(task, 1)" disabled="@isProcessing">Move Right →</button>
                                }
                            </div>
                        </div>
                    }
                </div>
                @if (addingToColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" class="form-control mb-1" placeholder="Title" @bind="newTitle" />
                        <input type="text" class="form-control mb-1" placeholder="Assignee" @bind="newAssignee" />
                        <select class="form-select mb-1" @bind="newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control mb-1" @bind="newDueDate" />
                        <div class="d-flex gap-1">
                            <button class="btn btn-sm btn-primary" @onclick="SaveNewTask" disabled="@isProcessing">Save</button>
                            <button class="btn btn-sm btn-secondary" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary add-task-btn" @onclick="() => StartAdd(column)">+ Add Task</button>
                }
            </div>
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private bool isProcessing;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today;

    private readonly string[] columns = { "To Do", "In Progress", "Done" };

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status) =>
        allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(searchQuery) || t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private int GetColumnIndex(string column) => Array.IndexOf(columns, column);

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = GetColumnIndex(task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        isProcessing = true;
        try
        {
            var newStatus = columns[newIndex];
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            // Update local state
            var idx = allTasks.FindIndex(t => t.Id == task.Id);
            if (idx >= 0)
                allTasks[idx] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            isProcessing = false;
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today;
    }

    private void CancelAdd() => addingToColumn = null;

    private async Task SaveNewTask()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || addingToColumn is null) return;

        isProcessing = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            allTasks.Add(created);
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isProcessing = false;
        }
    }
}

